async function startSiweFlow(address) {
  const res = await fetch('/functions/v1/siwe-nonce', { method: 'POST', body: JSON.stringify({ address }), headers: { 'Content-Type': 'application/json' } });
  const { message } = await res.json();
  let signature;
  try {
    const { signMessage } = await import('https://esm.sh/wagmi@1/actions');
    signature = await signMessage({ message });
  } catch (e) { showError('Signature cancelled'); return; }
  const verifyRes = await fetch('/functions/v1/siwe-verify', { method: 'POST', body: JSON.stringify({ message, signature, address }), headers: { 'Content-Type': 'application/json' } });
  if (!verifyRes.ok) { showError('Sign-in failed, please try again'); return; }
  const { url } = await verifyRes.json();
  window.location.href = url;
}
